import React, { useState } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { PlusCircle, Vote } from 'lucide-react';
import './css/PollsPage.css';

const PollsPage = () => {
    const [polls, setPolls] = useState([
        {
            id: 1,
            question: "What's your favorite programming language?",
            options: [
                { name: "JavaScript", votes: 30 },
                { name: "Python", votes: 25 },
                { name: "Java", votes: 20 },
                { name: "C++", votes: 15 },
            ],
            totalVotes: 90,
        },
        {
            id: 2,
            question: "Which frontend framework do you prefer?",
            options: [
                { name: "React", votes: 40 },
                { name: "Vue", votes: 30 },
                { name: "Angular", votes: 20 },
                { name: "Svelte", votes: 10 },
            ],
            totalVotes: 100,
        },
    ]);

    const [showCreatePoll, setShowCreatePoll] = useState(false);
    const [newPoll, setNewPoll] = useState({
        question: '',
        options: ['', ''],
    });

    const handleCreatePoll = (e) => {
        e.preventDefault();
        // Here we would normally send this to the backend
        // For now, we'll just add it to the local state
        const createdPoll = {
            id: polls.length + 1,
            question: newPoll.question,
            options: newPoll.options.map(option => ({ name: option, votes: 0 })),
            totalVotes: 0,
        };
        setPolls([...polls, createdPoll]);
        setShowCreatePoll(false);
        setNewPoll({ question: '', options: ['', ''] });
    };

    const handleAddOption = () => {
        setNewPoll({ ...newPoll, options: [...newPoll.options, ''] });
    };

    return (
        <div className="polls-page">
            <h1>User Polls</h1>
            <button className="create-poll-btn" onClick={() => setShowCreatePoll(!showCreatePoll)}>
                <PlusCircle size={20} />
                Create New Poll
            </button>

            {showCreatePoll && (
                <div className="create-poll-form">
                    <h2>Create a New Poll</h2>
                    <form onSubmit={handleCreatePoll}>
                        <input
                            type="text"
                            placeholder="Enter your question"
                            value={newPoll.question}
                            onChange={(e) => setNewPoll({ ...newPoll, question: e.target.value })}
                            required
                        />
                        {newPoll.options.map((option, index) => (
                            <input
                                key={index}
                                type="text"
                                placeholder={`Option ${index + 1}`}
                                value={option}
                                onChange={(e) => {
                                    const newOptions = [...newPoll.options];
                                    newOptions[index] = e.target.value;
                                    setNewPoll({ ...newPoll, options: newOptions });
                                }}
                                required
                            />
                        ))}
                        <button type="button" onClick={handleAddOption}>Add Option</button>
                        <button type="submit">Create Poll</button>
                    </form>
                </div>
            )}

            <div className="polls-list">
                {polls.map((poll) => (
                    <div key={poll.id} className="poll-item">
                        <h2>{poll.question}</h2>
                        <ResponsiveContainer width="100%" height={300}>
                            <BarChart data={poll.options}>
                                <CartesianGrid strokeDasharray="3 3" />
                                <XAxis dataKey="name" />
                                <YAxis />
                                <Tooltip />
                                <Legend />
                                <Bar dataKey="votes" fill="#8884d8" />
                            </BarChart>
                        </ResponsiveContainer>
                        <div className="poll-stats">
                            <Vote size={20} />
                            <span>Total Votes: {poll.totalVotes}</span>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default PollsPage;
